// userSlice.ts
import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface UserData {
  firstName: string;
  dob: any;
  mobile: string;
  sex: string;
  id: any;
  idType: any;
}
// interface userExtraData {
//   address: string;
//   state: any;
//   city: string;
//   country: string;
//   pinCode: any;
// }

interface UserState {
  userData: UserData;
  userExtraData: userExtraData;
}

const initialState: UserState = {
  userData: {
    firstName: '',
    dob: '',
    mobile: '',
    sex: '',
    id: '',
    idType: '',
  },
  userExtraData: {
    address: '',
    state: '',
    city: '',
    country: '',
    pinCode: '',
  },
};

const userSlice = createSlice({
  name: 'user',
  initialState,
  reducers: {
    updateUserData: (state, action: PayloadAction<UserData>) => {
      state.userData = { ...state.userData, ...action.payload };
    },
    resetUserData: (state) => {
      state.userData = initialState.userData;
    },
    updateUserExtraData: (state, action: PayloadAction<FormData>) => {
      // Update the user data accordingly
      // For example:
      state.userData.address = action.payload.address;
      state.userData.state = action.payload.state;
      state.userData.city = action.payload.city;
      state.userData.country = action.payload.country;
      state.userData.pinCode = action.payload.pinCode;
    },
    resetUserExtraData: (state) => {
      state.userExtraData = initialState.userExtraData;
    },
  },
});

export const {
  updateUserData,
  resetUserData,
  updateUserExtraData,
  resetUserExtraData,
} = userSlice.actions;
export default userSlice.reducer;
